// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";

/**
 * @title IdentityRegistry
 * @dev Manages decentralized identities and verifiable credentials for farmers and participants
 */
contract IdentityRegistry is AccessControl {
    using ECDSA for bytes32;

    // Role definitions
    bytes32 public constant ISSUER_ROLE = keccak256("ISSUER_ROLE");
    bytes32 public constant VERIFIER_ROLE = keccak256("VERIFIER_ROLE");

    // Credential types
    enum CredentialType {
        LAND_OWNERSHIP,
        CROP_HISTORY,
        CREDIT_HISTORY,
        KYC_VERIFICATION,
        OTHER
    }

    // Credential status
    enum CredentialStatus { ACTIVE, REVOKED, EXPIRED }

    // Verifiable Credential structure (simplified for MVP)
    struct VerifiableCredential {
        bytes32 id; // Unique identifier for the credential
        address subject; // DID of the credential subject
        CredentialType credType;
        string ipfsHash; // IPFS hash of the credential data
        address issuer; // DID of the issuer
        uint256 issuanceDate;
        uint256 expirationDate;
        CredentialStatus status;
    }

    // Decentralized Identity structure
    struct Identity {
        address owner;
        bool isActive;
        bytes32[] credentials; // Array of credential IDs
        mapping(bytes32 => bool) hasCredential; // Quick lookup for credentials
    }

    // State variables
    mapping(address => Identity) public identities;
    mapping(bytes32 => VerifiableCredential) public credentials;
    mapping(address => bool) public registeredDIDs;

    // Events
    event DIDRegistered(address indexed did, address owner);
    event CredentialIssued(
        bytes32 indexed credentialId,
        address indexed subject,
        CredentialType credType,
        address issuer
    );
    event CredentialRevoked(bytes32 indexed credentialId, address indexed issuer);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Register a new decentralized identity (DID)
     */
    function registerDID() external {
        require(!registeredDIDs[msg.sender], "DID already registered");

        Identity storage identity = identities[msg.sender];
        identity.owner = msg.sender;
        identity.isActive = true;

        registeredDIDs[msg.sender] = true;

        emit DIDRegistered(msg.sender, msg.sender);
    }

    /**
     * @dev Issue a new verifiable credential
     */
    function issueCredential(
        address subject,
        CredentialType credType,
        string memory ipfsHash,
        uint256 validityPeriod
    ) external onlyRole(ISSUER_ROLE) returns (bytes32) {
        require(registeredDIDs[subject], "Subject DID not registered");

        bytes32 credentialId = keccak256(
            abi.encodePacked(
                subject,
                credType,
                block.timestamp,
                ipfsHash,
                msg.sender
            )
        );

        VerifiableCredential storage cred = credentials[credentialId];
        cred.id = credentialId;
        cred.subject = subject;
        cred.credType = credType;
        cred.ipfsHash = ipfsHash;
        cred.issuer = msg.sender;
        cred.issuanceDate = block.timestamp;
        cred.expirationDate = block.timestamp + validityPeriod;
        cred.status = CredentialStatus.ACTIVE;

        // Add to subject's identity
        Identity storage subjectIdentity = identities[subject];
        subjectIdentity.credentials.push(credentialId);
        subjectIdentity.hasCredential[credentialId] = true;

        emit CredentialIssued(credentialId, subject, credType, msg.sender);

        return credentialId;
    }

    /**
     * @dev Revoke a credential
     */
    function revokeCredential(bytes32 credentialId) external onlyRole(ISSUER_ROLE) {
        VerifiableCredential storage cred = credentials[credentialId];
        require(cred.issuer == msg.sender, "Not the issuer of this credential");
        require(cred.status == CredentialStatus.ACTIVE, "Credential not active");

        cred.status = CredentialStatus.REVOKED;

        emit CredentialRevoked(credentialId, msg.sender);
    }

    /**
     * @dev Verify a credential's validity
     */
    function verifyCredential(bytes32 credentialId) external view returns (bool) {
        VerifiableCredential storage cred = credentials[credentialId];

        return (
            cred.status == CredentialStatus.ACTIVE &&
            cred.expirationDate > block.timestamp
        );
    }

    /**
     * @dev Get credentials for a DID
     */
    function getCredentials(address did) external view returns (bytes32[] memory) {
        return identities[did].credentials;
    }

    /**
     * @dev Get credential details
     */
    function getCredential(bytes32 credentialId) external view returns (
        bytes32 id,
        address subject,
        CredentialType credType,
        string memory ipfsHash,
        address issuer,
        uint256 issuanceDate,
        uint256 expirationDate,
        CredentialStatus status
    ) {
        VerifiableCredential storage cred = credentials[credentialId];
        return (
            cred.id,
            cred.subject,
            cred.credType,
            cred.ipfsHash,
            cred.issuer,
            cred.issuanceDate,
            cred.expirationDate,
            cred.status
        );
    }
}

contracts/InvestmentManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/Counters.sol";
import "./ProjectFactory.sol";

/**
 * @title InvestmentManager
 * @dev Manages USDC investments in farming projects
 */
contract InvestmentManager is AccessControl, ReentrancyGuard {
    using Counters for Counters.Counter;
    using SafeERC20 for IERC20;

    // Role definitions
    bytes32 public constant INVESTOR_ROLE = keccak256("INVESTOR_ROLE");
    bytes32 public constant PROJECT_MANAGER_ROLE = keccak256("PROJECT_MANAGER_ROLE");

    // Investment structure
    struct Investment {
        address investor;
        uint256 projectId;
        uint256 amountUSDC; // Amount in USDC (6 decimals)
        uint256 timestamp;
        bool claimed;
        uint256 expectedReturnUSDC; // Expected return in USDC
    }

    // State variables
    ProjectFactory public projectFactory;
    IERC20 public immutable USDC;

    mapping(uint256 => Investment[]) public projectInvestments; // projectId => Investment[]
    mapping(address => uint256[]) public investorProjects; // investor => projectId[]
    mapping(address => mapping(uint256 => uint256)) public investorProjectAmount; // investor => projectId => amount USDC
    mapping(uint256 => uint256) public projectFunding; // projectId => total funded amount USDC

    // Investment limits and fees
    uint256 public constant MIN_INVESTMENT_USDC = 10 * 1e6; // 10 USDC minimum
    uint256 public constant PLATFORM_FEE_PERCENT = 150; // 1.5% (scaled by 10000)

    // Events
    event Invested(
        address indexed investor, 
        uint256 indexed projectId, 
        uint256 amountUSDC, 
        uint256 amountBDT
    );
    event Withdrawn(address indexed investor, uint256 indexed projectId, uint256 amountUSDC);
    event PlatformFeeCollected(uint256 projectId, uint256 feeUSDC);

    constructor(address _projectFactoryAddress, address _usdcAddress) {
        require(_projectFactoryAddress != address(0), "Invalid project factory address");
        require(_usdcAddress != address(0), "Invalid USDC address");

        projectFactory = ProjectFactory(_projectFactoryAddress);
        USDC = IERC20(_usdcAddress);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Invest USDC in a project
     * @param projectId ID of the project to invest in
     * @param amountUSDC Amount to invest in USDC (6 decimals)
     */
    function invest(uint256 projectId, uint256 amountUSDC) external nonReentrant onlyRole(INVESTOR_ROLE) {
        require(amountUSDC >= MIN_INVESTMENT_USDC, "Investment below minimum");
        require(USDC.balanceOf(msg.sender) >= amountUSDC, "Insufficient USDC balance");

        // Get project details
        ProjectFactory.Project memory project = projectFactory.getProject(projectId);
        require(project.status == ProjectFactory.ProjectStatus.Approved, "Project not available for investment");
        require(projectFunding[projectId] + amountUSDC <= project.targetAmountUSDC, "Investment exceeds target");

        // Transfer USDC from investor
        USDC.safeTransferFrom(msg.sender, address(this), amountUSDC);

        // Calculate platform fee
        uint256 platformFee = (amountUSDC * PLATFORM_FEE_PERCENT) / 10000;
        uint256 netInvestment = amountUSDC - platformFee;

        // Update project funding
        projectFunding[projectId] += netInvestment;

        // Calculate expected return (example: 12% annual return, prorated)
        uint256 expectedReturn = calculateExpectedReturn(netInvestment, 90); // 90 days default

        // Create investment record
        Investment memory newInvestment = Investment({
            investor: msg.sender,
            projectId: projectId,
            amountUSDC: netInvestment,
            timestamp: block.timestamp,
            claimed: false,
            expectedReturnUSDC: expectedReturn
        });

        projectInvestments[projectId].push(newInvestment);

        // Update investor tracking
        if (investorProjectAmount[msg.sender][projectId] == 0) {
            investorProjects[msg.sender].push(projectId);
        }
        investorProjectAmount[msg.sender][projectId] += netInvestment;

        // Update project funding in ProjectFactory
        projectFactory.updateFunding(projectId, netInvestment);

        // Convert to BDT for display purposes
        uint256 amountBDT = projectFactory.convertUSDCToBDT(amountUSDC);

        emit Invested(msg.sender, projectId, amountUSDC, amountBDT);
        emit PlatformFeeCollected(projectId, platformFee);
    }

    /**
     * @dev Calculate expected return for an investment
     * @param amountUSDC Investment amount in USDC
     * @param durationDays Duration in days
     * @return Expected return in USDC
     */
    function calculateExpectedReturn(uint256 amountUSDC, uint256 durationDays) public pure returns (uint256) {
        // 12% annual return = 12% / 365 days
        // Return = principal * rate * time
        uint256 dailyRate = 1200; // 12% * 100 for precision
        return (amountUSDC * dailyRate * durationDays) / (365 * 10000);
    }

    /**
     * @dev Get total funding for a project in USDC
     * @param projectId ID of the project
     * @return Total amount funded in USDC
     */
    function getProjectFundingUSDC(uint256 projectId) external view returns (uint256) {
        return projectFunding[projectId];
    }

    /**
     * @dev Get total funding for a project in BDT
     * @param projectId ID of the project
     * @return Total amount funded in BDT (scaled by 100)
     */
    function getProjectFundingBDT(uint256 projectId) external view returns (uint256) {
        return projectFactory.convertUSDCToBDT(projectFunding[projectId]);
    }

    /**
     * @dev Get investments by project ID
     * @param projectId ID of the project
     * @return Array of investments in the project
     */
    function getProjectInvestments(uint256 projectId) external view returns (Investment[] memory) {
        return projectInvestments[projectId];
    }

    /**
     * @dev Get investor's projects
     * @param investor Address of the investor
     * @return Array of project IDs the investor has invested in
     */
    function getInvestorProjects(address investor) external view returns (uint256[] memory) {
        return investorProjects[investor];
    }

    /**
     * @dev Get investor's investment details for a project
     * @param investor Address of the investor
     * @param projectId ID of the project
     * @return amountUSDC Total USDC invested
     * @return amountBDT Total BDT equivalent
     * @return expectedReturnUSDC Expected return in USDC
     */
    function getInvestorProjectDetails(address investor, uint256 projectId) 
        external view returns (uint256 amountUSDC, uint256 amountBDT, uint256 expectedReturnUSDC) 
    {
        amountUSDC = investorProjectAmount[investor][projectId];
        amountBDT = projectFactory.convertUSDCToBDT(amountUSDC);

        // Calculate total expected return for this investor in this project
        Investment[] memory investments = projectInvestments[projectId];
        for (uint256 i = 0; i < investments.length; i++) {
            if (investments[i].investor == investor) {
                expectedReturnUSDC += investments[i].expectedReturnUSDC;
            }
        }
    }

    /**
     * @dev Get investment share percentage for an investor in a project
     * @param investor Address of the investor
     * @param projectId ID of the project
     * @return Share percentage (scaled by 10000, so 100% = 10000)
     */
    function getInvestmentShare(address investor, uint256 projectId) external view returns (uint256) {
        uint256 totalFunding = projectFunding[projectId];
        if (totalFunding == 0) return 0;

        uint256 investorAmount = investorProjectAmount[investor][projectId];
        return (investorAmount * 10000) / totalFunding;
    }

    /**
     * @dev Transfer funds to farmer upon project milestone completion
     * @param projectId ID of the project
     * @param amountUSDC Amount to transfer in USDC
     * @param farmer Address of the farmer
     */
    function releaseFundsToFarmer(
        uint256 projectId, 
        uint256 amountUSDC, 
        address farmer
    ) external onlyRole(PROJECT_MANAGER_ROLE) {
        require(projectFunding[projectId] >= amountUSDC, "Insufficient project funds");

        projectFunding[projectId] -= amountUSDC;
        USDC.safeTransfer(farmer, amountUSDC);
    }

    /**
     * @dev Emergency withdraw function (admin only)
     */
    function emergencyWithdraw(uint256 amountUSDC) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(USDC.balanceOf(address(this)) >= amountUSDC, "Insufficient contract balance");
        USDC.safeTransfer(msg.sender, amountUSDC);
    }

    /**
     * @dev Get contract USDC balance
     */
    function getContractBalance() external view returns (uint256) {
        return USDC.balanceOf(address(this));
    }

    /**
     * @dev Approve this contract to spend investor's USDC (helper function)
     * @param amountUSDC Amount to approve
     */
    function getApprovalData(uint256 amountUSDC) external view returns (address, bytes memory) {
        return (address(USDC), abi.encodeWithSignature("approve(address,uint256)", address(this), amountUSDC));
    }
}

contracts/OracleIntegration.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "./ProjectFactory.sol";

/**
 * @title OracleIntegration
 * @dev Handles verification of project milestones and data from multiple sources
 */
contract OracleIntegration is AccessControl {
    // Role definitions
    bytes32 public constant ORACLE_NODE = keccak256("ORACLE_NODE");
    bytes32 public constant NGO_AGENT = keccak256("NGO_AGENT");

    // Data source types
    enum DataSource { NGO, IOT, SATELLITE, CHAINLINK }

    // Verification status
    enum VerificationStatus { Pending, Verified, Rejected, Disputed }

    // Milestone structure
    struct Milestone {
        uint256 projectId;
        uint256 milestoneId;
        string description;
        uint256 targetDate;
        uint256 completionDate;
        VerificationStatus status;
        string ipfsHash; // For supporting documents
        address verifiedBy;
        DataSource source;
    }

    // State variables
    ProjectFactory public projectFactory;
    uint256 public verificationThreshold = 2; // Number of verifications required
    mapping(uint256 => Milestone[]) public projectMilestones; // projectId => Milestone[]
    mapping(bytes32 => address[]) public milestoneVerifiers; // milestoneHash => verifierAddresses[]

    // Events
    event MilestoneAdded(uint256 indexed projectId, uint256 milestoneId, string description);
    event MilestoneVerified(uint256 indexed projectId, uint256 milestoneId, address verifier, DataSource source);
    event MilestoneStatusUpdated(uint256 indexed projectId, uint256 milestoneId, VerificationStatus status);
    event DisputeRaised(uint256 indexed projectId, uint256 milestoneId, address raisedBy);

    constructor(address _projectFactoryAddress) {
        require(_projectFactoryAddress != address(0), "Invalid project factory address");
        projectFactory = ProjectFactory(_projectFactoryAddress);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Add a new milestone to a project (only callable by project owner or admin)
     */
    function addMilestone(
        uint256 projectId,
        string memory description,
        uint256 targetDate,
        string memory ipfsHash
    ) external {
        // Verify sender is project owner or admin
        (bool success, bytes memory data) = address(projectFactory).staticcall(
            abi.encodeWithSignature("getProject(uint256)", projectId)
        );
        require(success, "Failed to fetch project details");

        ProjectFactory.Project memory project = abi.decode(data, (ProjectFactory.Project));
        require(
            project.farmer == msg.sender || hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Not authorized to add milestone"
        );

        uint256 milestoneId = projectMilestones[projectId].length;

        projectMilestones[projectId].push(Milestone({
            projectId: projectId,
            milestoneId: milestoneId,
            description: description,
            targetDate: targetDate,
            completionDate: 0,
            status: VerificationStatus.Pending,
            ipfsHash: ipfsHash,
            verifiedBy: address(0),
            source: DataSource.NGO // Default source
        }));

        emit MilestoneAdded(projectId, milestoneId, description);
    }

    /**
     * @dev Verify a milestone (callable by oracle nodes or NGO agents)
     */
    function verifyMilestone(
        uint256 projectId,
        uint256 milestoneId,
        bool isVerified,
        DataSource source
    ) external onlyRole(ORACLE_NODE) {
        require(projectId < projectMilestones[projectId].length, "Milestone does not exist");
        Milestone storage milestone = projectMilestones[projectId][milestoneId];

        require(
            milestone.status == VerificationStatus.Pending ||
            milestone.status == VerificationStatus.Disputed,
            "Milestone already processed"
        );

        // Record verification
        bytes32 milestoneHash = keccak256(abi.encodePacked(projectId, milestoneId));
        milestoneVerifiers[milestoneHash].push(msg.sender);

        emit MilestoneVerified(projectId, milestoneId, msg.sender, source);

        // Check if enough verifications are received
        if (milestoneVerifiers[milestoneHash].length >= verificationThreshold) {
            milestone.status = isVerified ? 
                VerificationStatus.Verified : 
                VerificationStatus.Rejected;
            milestone.completionDate = block.timestamp;
            milestone.verifiedBy = msg.sender;
            milestone.source = source;

            emit MilestoneStatusUpdated(projectId, milestoneId, milestone.status);
        }
    }

    /**
     * @dev Raise a dispute for a milestone
     */
    function raiseDispute(uint256 projectId, uint256 milestoneId) external {
        require(projectId < projectMilestones[projectId].length, "Milestone does not exist");
        Milestone storage milestone = projectMilestones[projectId][milestoneId];

        require(
            milestone.status == VerificationStatus.Verified ||
            milestone.status == VerificationStatus.Rejected,
            "Cannot dispute pending milestone"
        );

        milestone.status = VerificationStatus.Disputed;
        emit DisputeRaised(projectId, milestoneId, msg.sender);
    }

    /**
     * @dev Get all milestones for a project
     */
    function getProjectMilestones(uint256 projectId) external view returns (Milestone[] memory) {
        return projectMilestones[projectId];
    }

    /**
     * @dev Update verification threshold (admin only)
     */
    function setVerificationThreshold(uint256 _threshold) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(_threshold > 0, "Threshold must be greater than 0");
        verificationThreshold = _threshold;
    }
}

contracts/ProjectFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Counters.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title ProjectFactory
 * @dev Manages farming projects with BDT amounts and USDC funding
 */
contract ProjectFactory is AccessControl {
    using Counters for Counters.Counter;

    // Role definitions
    bytes32 public constant FARMER_ROLE = keccak256("FARMER_ROLE");
    bytes32 public constant VALIDATOR_ROLE = keccak256("VALIDATOR_ROLE");

    // Project status enum
    enum ProjectStatus { Pending, Approved, Rejected, Active, Completed, Defaulted }

    // Project structure
    struct Project {
        uint256 id;
        address farmer;
        string title;
        string description;
        string ipfsHash; // IPFS CID for project documents
        uint256 targetAmountBDT; // Target amount in BDT (scaled by 100, so 100000 BDT = 10000000)
        uint256 targetAmountUSDC; // Target amount in USDC (6 decimals)
        uint256 fundedAmountUSDC; // Funded amount in USDC (6 decimals)
        uint256 startDate;
        uint256 endDate;
        ProjectStatus status;
        bool isVerified;
        string location; // Project location
        string category; // Crop type/category
    }

    // Constants for BDT/USDC conversion
    uint256 public constant BDT_TO_USDC_RATE = 125; // 1 BDT = 125 USDC (scaled by 1e6)
    uint256 public constant BDT_DECIMALS = 100; // BDT amounts scaled by 100 (2 decimals)

    // USDC token interface
    IERC20 public immutable USDC;

    // State variables
    Counters.Counter private _projectIds;
    mapping(uint256 => Project) public projects;
    mapping(address => uint256[]) public farmerProjects;

    // Events
    event ProjectCreated(
        uint256 indexed projectId, 
        address indexed farmer, 
        string ipfsHash,
        uint256 targetAmountBDT,
        uint256 targetAmountUSDC
    );
    event ProjectVerified(uint256 indexed projectId, address indexed validator, bool isApproved);
    event ProjectFunded(uint256 indexed projectId, uint256 amountUSDC, uint256 totalFundedUSDC);

    constructor(address _usdcAddress) {
        require(_usdcAddress != address(0), "Invalid USDC address");
        USDC = IERC20(_usdcAddress);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    /**
     * @dev Create a new farming project with BDT target amount
     * @param title Project title
     * @param description Project description
     * @param ipfsHash IPFS hash containing project documents
     * @param targetAmountBDT Target amount in BDT (scaled by 100, so 100000 BDT = 10000000)
     * @param durationInDays Project duration in days
     * @param location Project location
     * @param category Project category
     */
    function createProject(
        string memory title,
        string memory description,
        string memory ipfsHash,
        uint256 targetAmountBDT,
        uint256 durationInDays,
        string memory location,
        string memory category
    ) external onlyRole(FARMER_ROLE) {
        require(bytes(title).length > 0, "Title cannot be empty");
        require(targetAmountBDT > 0, "Target amount must be greater than 0");
        require(durationInDays > 0, "Duration must be greater than 0");

        _projectIds.increment();
        uint256 projectId = _projectIds.current();

        // Convert BDT to USDC (targetAmountBDT is scaled by 100, USDC has 6 decimals)
        // Formula: (targetAmountBDT / 100) / 125 * 1e6
        uint256 targetAmountUSDC = (targetAmountBDT * 1e6) / (BDT_TO_USDC_RATE * BDT_DECIMALS);

        projects[projectId] = Project({
            id: projectId,
            farmer: msg.sender,
            title: title,
            description: description,
            ipfsHash: ipfsHash,
            targetAmountBDT: targetAmountBDT,
            targetAmountUSDC: targetAmountUSDC,
            fundedAmountUSDC: 0,
            startDate: 0, // Will be set when project is approved
            endDate: 0,   // Will be set when project is approved
            status: ProjectStatus.Pending,
            isVerified: false,
            location: location,
            category: category
        });

        farmerProjects[msg.sender].push(projectId);

        emit ProjectCreated(projectId, msg.sender, ipfsHash, targetAmountBDT, targetAmountUSDC);
    }

    /**
     * @dev Verify a project (only callable by validators)
     * @param projectId ID of the project to verify
     * @param isApproved Whether the project is approved
     */
    function verifyProject(uint256 projectId, bool isApproved) external onlyRole(VALIDATOR_ROLE) {
        Project storage project = projects[projectId];
        require(project.id != 0, "Project does not exist");
        require(project.status == ProjectStatus.Pending, "Project already processed");

        if (isApproved) {
            project.status = ProjectStatus.Approved;
            project.isVerified = true;
            project.startDate = block.timestamp;
            project.endDate = block.timestamp + (90 days); // Default 90-day project duration
        } else {
            project.status = ProjectStatus.Rejected;
        }

        emit ProjectVerified(projectId, msg.sender, isApproved);
    }

    /**
     * @dev Update funded amount (called by InvestmentManager)
     * @param projectId ID of the project
     * @param amountUSDC Amount funded in USDC
     */
    function updateFunding(uint256 projectId, uint256 amountUSDC) external {
        // Only InvestmentManager should call this - we'll add proper access control
        Project storage project = projects[projectId];
        require(project.id != 0, "Project does not exist");

        project.fundedAmountUSDC += amountUSDC;

        // Check if project is fully funded
        if (project.fundedAmountUSDC >= project.targetAmountUSDC) {
            project.status = ProjectStatus.Active;
        }

        emit ProjectFunded(projectId, amountUSDC, project.fundedAmountUSDC);
    }

    /**
     * @dev Get projects by farmer address
     * @param farmer Address of the farmer
     * @return Array of project IDs
     */
    function getProjectsByFarmer(address farmer) external view returns (uint256[] memory) {
        return farmerProjects[farmer];
    }

    /**
     * @dev Get project details by ID
     * @param projectId ID of the project
     * @return project The project details
     */
    function getProject(uint256 projectId) external view returns (Project memory) {
        require(projects[projectId].id != 0, "Project does not exist");
        return projects[projectId];
    }

    /**
     * @dev Convert BDT amount to USDC
     * @param amountBDT Amount in BDT (scaled by 100)
     * @return Amount in USDC (6 decimals)
     */
    function convertBDTToUSDC(uint256 amountBDT) external pure returns (uint256) {
        return (amountBDT * 1e6) / (BDT_TO_USDC_RATE * BDT_DECIMALS);
    }

    /**
     * @dev Convert USDC amount to BDT
     * @param amountUSDC Amount in USDC (6 decimals)
     * @return Amount in BDT (scaled by 100)
     */
    function convertUSDCToBDT(uint256 amountUSDC) external pure returns (uint256) {
        return (amountUSDC * BDT_TO_USDC_RATE * BDT_DECIMALS) / 1e6;
    }

    /**
     * @dev Get funding progress as percentage
     * @param projectId ID of the project
     * @return Percentage funded (scaled by 100, so 100% = 10000)
     */
    function getFundingProgress(uint256 projectId) external view returns (uint256) {
        Project memory project = projects[projectId];
        if (project.targetAmountUSDC == 0) return 0;

        return (project.fundedAmountUSDC * 10000) / project.targetAmountUSDC;
    }

    /**
     * @dev Get total number of projects
     */
    function getTotalProjects() external view returns (uint256) {
        return _projectIds.current();
    }
}

